/**
 * my_stdlib.c - Minimal standard library implementation
 * Contains stubs for all functions declared in my_stdlib.h
 */

#include "my_stdlib.h"

// System call numbers
#define SYS_read    0
#define SYS_write   1
#define SYS_open    2
#define SYS_close   3
#define SYS_lseek   8
