#!/usr/bin/env node
// MIPS32r2 (o32, little-endian) user-mode interpreter for doomgeneric_mips.
// Loads the ELF, emulates the CPU + the handful of Linux syscalls the binary
// actually issues, and persists each rendered frame to /tmp/frame.bmp.
'use strict';
const fs = require('fs');
const path = require('path');

const ELF_PATH = process.argv[2] || path.join(__dirname, 'doomgeneric_mips');
const WAD_DIRS = [process.cwd(), __dirname, '/app'];
const FRAME_PATH = '/tmp/frame.bmp';

// ---------------------------------------------------------------------------
// Guest memory. Guest addresses map 1:1 onto the backing array index.
// bss (incl. the 1GB static heap) tops out ~0x404b1790 but the program only
// ever touches the low part of the heap plus the stack, so 256MB is plenty.
// ---------------------------------------------------------------------------
const MEM_SIZE = 0x10000000; // 256 MiB
const membuf = new ArrayBuffer(MEM_SIZE);
const u8 = new Uint8Array(membuf);
const mem32 = new Int32Array(membuf); // aligned 32-bit access (fetch, lw/sw)
const dv = new DataView(membuf);

const STACK_TOP = 0x0ffffff0; // 8-byte aligned, well above heap growth

// ---------------------------------------------------------------------------
// ELF loader (ELF32 LE, program headers only).
// ---------------------------------------------------------------------------
function loadElf(file) {
  const b = fs.readFileSync(file);
  if (b[0] !== 0x7f || b[1] !== 0x45 || b[2] !== 0x4c || b[3] !== 0x46)
    throw new Error('not an ELF');
  const entry = b.readUInt32LE(24);
  const phoff = b.readUInt32LE(28);
  const phentsize = b.readUInt16LE(42);
  const phnum = b.readUInt16LE(44);
  for (let i = 0; i < phnum; i++) {
    const o = phoff + i * phentsize;
    const type = b.readUInt32LE(o);
    if (type !== 1) continue; // PT_LOAD
    const off = b.readUInt32LE(o + 4);
    const vaddr = b.readUInt32LE(o + 8);
    const filesz = b.readUInt32LE(o + 16);
    // memsz beyond filesz is bss -> already zero.
    u8.set(b.subarray(off, off + filesz), vaddr);
  }
  return entry >>> 0;
}

// ---------------------------------------------------------------------------
// Register file / CPU state.
// ---------------------------------------------------------------------------
const reg = new Int32Array(32);
let HI = 0, LO = 0;
const fgr = new Uint32Array(32); // FPU registers (FR=0: doubles use even/odd pair)
const fcc = new Uint8Array(8);   // FP condition codes

// float bit-reinterpret helpers
const fbuf = new ArrayBuffer(8);
const f32 = new Float32Array(fbuf);
const f64 = new Float64Array(fbuf);
const fu32 = new Uint32Array(fbuf);
function rS(i) { fu32[0] = fgr[i]; return f32[0]; }
function wS(i, v) { f32[0] = v; fgr[i] = fu32[0]; }
function rD(i) { fu32[0] = fgr[i]; fu32[1] = fgr[i + 1]; return f64[0]; }
function wD(i, v) { f64[0] = v; fgr[i] = fu32[0]; fgr[i + 1] = fu32[1]; }

// ---------------------------------------------------------------------------
// Real-file syscall backing (only doom.wad is opened for real).
// ---------------------------------------------------------------------------
const openFiles = new Map();
let nextFd = 3;
function readCString(addr) {
  let s = '';
  addr >>>= 0;
  for (;;) {
    const c = u8[addr++];
    if (c === 0) break;
    s += String.fromCharCode(c);
  }
  return s;
}
function sysOpen(pathAddr) {
  const name = readCString(pathAddr);
  let data = null;
  const candidates = name[0] === '/' ? [name] : WAD_DIRS.map((d) => path.join(d, name));
  for (const p of candidates) {
    try { data = fs.readFileSync(p); break; } catch (e) { /* try next */ }
  }
  if (!data) return -2; // -ENOENT
  const fd = nextFd++;
  openFiles.set(fd, { buf: data, pos: 0 });
  return fd;
}

let frameCount = 0;
function saveFrame(srcAddr, size) {
  const out = Buffer.from(membuf, srcAddr >>> 0, size);
  fs.writeFileSync(FRAME_PATH, out);
  frameCount++;
  process.stderr.write(`[vm] saved frame #${frameCount} (${size} bytes) -> ${FRAME_PATH}\n`);
}

function doSyscall() {
  const v0 = reg[2];
  const a0 = reg[4], a1 = reg[5], a2 = reg[6];
  switch (v0) {
    case 0: { // read
      const f = openFiles.get(a0);
      if (!f) { reg[2] = -9; break; }
      const n = Math.min(a2 >>> 0, f.buf.length - f.pos);
      if (n > 0) { u8.set(f.buf.subarray(f.pos, f.pos + n), a1 >>> 0); f.pos += n; }
      reg[2] = n;
      break;
    }
    case 1: { // write
      if (a0 === 1 || a0 === 2) {
        const len = a2 >>> 0;
        if (len > 0) fs.writeSync(a0, Buffer.from(membuf, a1 >>> 0, len));
        reg[2] = len;
      } else reg[2] = -9;
      break;
    }
    case 2: reg[2] = sysOpen(a1); break;              // open(path=a1)  (a0 unused here)
    case 3: { openFiles.delete(a0); reg[2] = 0; break; } // close
    case 8: { // lseek
      const f = openFiles.get(a0);
      if (!f) { reg[2] = -9; break; }
      const whence = a2, off = a1 | 0;
      f.pos = whence === 0 ? off : whence === 1 ? f.pos + off : f.buf.length + off;
      reg[2] = f.pos;
      break;
    }
    case 60: // exit
      process.stderr.write(`[vm] guest exit(${a0})\n`);
      process.exit(a0 & 0xff);
      break;
    case 201: { // time
      const t = Math.floor(Date.now() / 1000);
      if (a0) mem32[(a0 >>> 0) >>> 2] = t;
      reg[2] = t;
      break;
    }
    default:
      reg[2] = 0; // gettimeofday/nanosleep/etc: benign success
      break;
  }
}

