// writeBMPFile (DG_DrawFrame), $s1 points at the complete BMP image.
const FRAME_HOOK_PC = 0x439748;
const FRAME_SIZE = 54 + 640 * 400 * 4; // 1024054 bytes

function run() {
  let count = 0;
  while (count < INSTR_LIMIT) {
    const pc = PC;

    if (pc === FRAME_HOOK_PC) {
      saveFrame(reg[17] >>> 0, FRAME_SIZE);
      process.stderr.write('[vm] first frame captured, exiting.\n');
      process.exit(0);
    }

    const inst = mem32[pc >>> 2] >>> 0;
    const op = inst >>> 26;
    const rs = (inst >>> 21) & 0x1f;
    const rt = (inst >>> 16) & 0x1f;
    const rd = (inst >>> 11) & 0x1f;
    const sa = (inst >>> 6) & 0x1f;
    const funct = inst & 0x3f;
    const imm = (inst << 16) >> 16;      // sign-extended immediate
    const uimm = inst & 0xffff;          // zero-extended immediate

    let target = (nPC + 4) >>> 0;        // default next-next PC (sequential)

    switch (op) {
      case 0x00: { // SPECIAL
        switch (funct) {
          case 0x00: reg[rd] = reg[rt] << sa; break;                 // sll
          case 0x02: // srl / rotr
            if ((inst >> 21) & 1) reg[rd] = (reg[rt] >>> sa) | (reg[rt] << (32 - sa) || 0);
            else reg[rd] = reg[rt] >>> sa;
            if (((inst >> 21) & 1) && sa === 0) reg[rd] = reg[rt];
            break;
          case 0x03: reg[rd] = reg[rt] >> sa; break;                 // sra
          case 0x04: reg[rd] = reg[rt] << (reg[rs] & 31); break;     // sllv
          case 0x06: { // srlv / rotrv
            const s = reg[rs] & 31;
            if ((inst >> 6) & 1) reg[rd] = s === 0 ? reg[rt] : (reg[rt] >>> s) | (reg[rt] << (32 - s));
            else reg[rd] = reg[rt] >>> s;
