          case 0x08: target = reg[rs] >>> 0; break;                  // jr
          case 0x09: reg[rd] = (pc + 8) | 0; target = reg[rs] >>> 0; break; // jalr
          case 0x0a: if (reg[rt] === 0) reg[rd] = reg[rs]; break;    // movz
          case 0x0b: if (reg[rt] !== 0) reg[rd] = reg[rs]; break;    // movn
          case 0x0c: doSyscall(); break;                            // syscall
          case 0x0d: doSyscall(); break;                            // break (unused) - treat benign
          case 0x10: reg[rd] = HI; break;                           // mfhi
          case 0x11: HI = reg[rs]; break;                           // mthi
          case 0x12: reg[rd] = LO; break;                           // mflo
          case 0x13: LO = reg[rs]; break;                           // mtlo
          case 0x18: { // mult
            const p = BigInt(reg[rs]) * BigInt(reg[rt]);
            LO = Number(p & 0xffffffffn) | 0;
            HI = Number((p >> 32n) & 0xffffffffn) | 0;
            break;
          }
