            break;
          case 0x1b: { // divu
            const a = reg[rs] >>> 0, b = reg[rt] >>> 0;
            if (b !== 0) { LO = Math.floor(a / b) | 0; HI = (a % b) | 0; }
            break;
          }
          case 0x20: reg[rd] = (reg[rs] + reg[rt]) | 0; break;       // add
          case 0x21: reg[rd] = (reg[rs] + reg[rt]) | 0; break;       // addu
          case 0x22: reg[rd] = (reg[rs] - reg[rt]) | 0; break;       // sub
          case 0x23: reg[rd] = (reg[rs] - reg[rt]) | 0; break;       // subu
          case 0x24: reg[rd] = reg[rs] & reg[rt]; break;            // and
          case 0x25: reg[rd] = reg[rs] | reg[rt]; break;            // or
          case 0x26: reg[rd] = reg[rs] ^ reg[rt]; break;            // xor
          case 0x27: reg[rd] = ~(reg[rs] | reg[rt]); break;         // nor
