      case 0x3d: { const a = (reg[rs] + imm) >>> 0; mem32[a >>> 2] = fgr[rt] | 0; mem32[(a + 4) >>> 2] = fgr[rt + 1] | 0; break; } // sdc1
      default:
        throw new Error('unhandled opcode 0x' + op.toString(16) + ' @0x' + pc.toString(16));
    }

    reg[0] = 0; // $zero stays wired to 0
    PC = nPC;
    nPC = target;
    count++;
  }
  process.stderr.write('[vm] instruction limit reached without capturing a frame\n');
  process.exit(1);
}

